228	                        <span className="text-xs">{option.description}</span>
229	                      </span>
230	                      {selected ? (
231	                        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
232	                          Selected
233	                        </span>
234	                      ) : null}
235	                    </button>
236	                  );
237	                })}
238	              </div>
239	
240	              <p className="mt-4 text-xs text-muted-foreground">
241	                Active theme: <span className="font-medium text-foreground">{resolvedTheme}</span>
242	              </p>
243	            </section>
244	
245	            <section className="rounded-2xl border border-border bg-card p-5">
246	              <div className="mb-4">
247	                <h2 className="text-sm font-medium text-foreground">Codex App Server</h2>
