512	                        enableAssistantStreaming: defaults.enableAssistantStreaming,
513	                      })
514	                    }
515	                  >
516	                    Restore default
517	                  </Button>
518	                </div>
519	              ) : null}
520	            </section>
521	
522	            <section className="rounded-2xl border border-border bg-card p-5">
523	              <div className="mb-4">
524	                <h2 className="text-sm font-medium text-foreground">Keybindings</h2>
525	                <p className="mt-1 text-xs text-muted-foreground">
526	                  Open the persisted <code>keybindings.json</code> file to edit advanced bindings
527	                  directly.
528	                </p>
529	              </div>
530	
531	              <div className="space-y-3">
532	                <div className="flex items-center justify-between gap-3 rounded-lg border border-border bg-background px-3 py-2">
533	                  <div className="min-w-0 flex-1">
