535	                    <p className="mt-1 break-all font-mono text-[11px] text-muted-foreground">
536	                      {keybindingsConfigPath ?? "Resolving keybindings path..."}
537	                    </p>
538	                  </div>
539	                  <Button
540	                    size="xs"
541	                    variant="outline"
542	                    disabled={!keybindingsConfigPath || isOpeningKeybindings}
543	                    onClick={openKeybindingsFile}
544	                  >
545	                    {isOpeningKeybindings ? "Opening..." : "Open keybindings.json"}
546	                  </Button>
