  const queryClient = new QueryClient();

  return createRouter({
    routeTree,
    history,
    context: {
      queryClient,
    },
    Wrap: ({ children }) =>
      createElement(
        QueryClientProvider,
        { client: queryClient },
        createElement(StoreProvider, null, children),  // Zustand provider
      ),
  });
}
```

**Provider stack (inside-out):**
1. React Query QueryClientProvider
2. Zustand StoreProvider
3. Child routes

#### **7.3 Zustand Store Pattern**

**File:** `store.ts`

```typescript
interface AppState {
  projects: Project[];
  threads: Thread[];
  threadsHydrated: boolean;
}

interface AppStore extends AppState {
  syncServerReadModel: (readModel: OrchestrationReadModel) => void;
  markThreadVisited: (threadId: ThreadId, visitedAt: number) => void;
  toggleProject: (projectId: ProjectId) => void;
  // ... other actions
}

const PERSISTED_STATE_KEY = "t3code:renderer-state:v8";

function readPersistedState(): AppState {
  // Reads from localStorage, handles migrations from legacy keys
}

function persistState(state: AppState): void {
  // Writes to localStorage
}

export const useStore = create<AppStore>((set) => ({
  ...readPersistedState(),
  syncServerReadModel: (readModel) => set((state) => syncServerReadModel(state, readModel)),
  // ... all actions
}));

// Auto-persist on every state change
useStore.subscribe((state) => persistState(state));

export function StoreProvider({ children }: { children: ReactNode }) {
  useEffect(() => {
    persistState(useStore.getState());
  }, []);
  return createElement(Fragment, null, children);
}
```

**Key patterns:**
- Pure state transition functions (pure functions that take state and return new state)
- Zustand `create()` with a function that receives `set`
- Persisted state stored in localStorage with versioning
- Explicit StoreProvider component with useEffect for hydration
- No return Fragment from provider - just returns children directly

---

### **8. UI COMPONENT PATTERNS**

#### **8.1 Base Component Pattern (Button Example)**

**File:** `components/ui/button.tsx`

```typescript
"use client";

import { mergeProps } from "@base-ui/react/merge-props";
import { useRender } from "@base-ui/react/use-render";
import { cva, type VariantProps } from "class-variance-authority";

const buttonVariants = cva(
  // Base classes
  "[&_svg]:-mx-0.5 relative inline-flex shrink-0 cursor-pointer items-center justify-center gap-2 ...",
  {
    defaultVariants: {
      size: "default",
      variant: "default",
    },
    variants: {
      size: {
        default: "h-9 px-[calc(--spacing(3)-1px)] sm:h-8",
        icon: "size-9 sm:size-8",
        // ... more sizes
      },
      variant: {
        default: "not-disabled:inset-shadow-[...] border-primary bg-primary ...",
        // ... more variants
      },
    },
  },
);

interface ButtonProps extends useRender.ComponentProps<"button"> {
  variant?: VariantProps<typeof buttonVariants>["variant"];
  size?: VariantProps<typeof buttonVariants>["size"];
}

function Button({ className, variant, size, render, ...props }: ButtonProps) {
  const typeValue = render ? undefined : "button";

  const defaultProps = {
    className: cn(buttonVariants({ className, size, variant })),
    "data-slot": "button",
    type: typeValue,
  };

  return useRender({
    defaultTagName: "button",
    props: mergeProps<"button">(defaultProps, props),
    render,
  });
}

export { Button, buttonVariants };
```

**Key patterns:**
- `"use client"` directive (for Next.js/Electron)
- CVA for variant management
- `cn()` for merging Tailwind classes (from lib/utils.ts)
- `useRender()` and `mergeProps()` from BaseUI for headless component composition
- `data-slot` attributes for CSS targeting
- Props include `className`, `render`, and type-specific props

#### **8.2 Utility Function Pattern**

**File:** `lib/utils.ts`

```typescript
import { type CxOptions, cx } from "class-variance-authority";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: CxOptions) {
  return twMerge(cx(inputs));
}

export const newCommandId = (): CommandId => CommandId.makeUnsafe(crypto.randomUUID());
export const newThreadId = (): ThreadId => ThreadId.makeUnsafe(crypto.randomUUID());
```

**Pattern:** Utility functions are straightforward, exported as named exports

#### **8.3 Custom Hook Pattern**

**File:** `hooks/useTheme.ts`

```typescript
type Theme = "light" | "dark" | "system";

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  // ...
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  // Setup listeners, return unsubscribe
  return () => { /* cleanup */ };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  // ... logic
  return { theme, setTheme, resolvedTheme } as const;
}
```

**Pattern:**
- Module-level state management for subscriptions
- `useSyncExternalStore` for external state synchronization
- Return object as `const` assertion for TypeScript inference
- Cleanup functions for event listeners

