551	                </p>
552	                {openKeybindingsError ? (
553	                  <p className="text-xs text-destructive">{openKeybindingsError}</p>
554	                ) : null}
555	              </div>
556	            </section>
557	
558	            <section className="rounded-2xl border border-border bg-card p-5">
559	              <div className="mb-4">
560	                <h2 className="text-sm font-medium text-foreground">Safety</h2>
561	                <p className="mt-1 text-xs text-muted-foreground">
562	                  Additional guardrails for destructive local actions.
563	                </p>
564	              </div>
565	
566	              <div className="flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
567	                <div>
568	                  <p className="text-sm font-medium text-foreground">Confirm thread deletion</p>
569	                  <p className="text-xs text-muted-foreground">
570	                    Ask for confirmation before deleting a thread and its chat history.
571	                  </p>
572	                </div>
573	                <Switch
574	                  checked={settings.confirmThreadDelete}
575	                  onCheckedChange={(checked) =>
576	                    updateSettings({
577	                      confirmThreadDelete: Boolean(checked),
578	                    })
579	                  }
580	                  aria-label="Confirm thread deletion"
581	                />
582	              </div>
583	
584	              {settings.confirmThreadDelete !== defaults.confirmThreadDelete ? (
585	                <div className="mt-3 flex justify-end">
586	                  <Button
587	                    size="xs"
588	                    variant="outline"
589	                    onClick={() =>
590	                      updateSettings({
591	                        confirmThreadDelete: defaults.confirmThreadDelete,
592	                      })
593	                    }
594	                  >
595	                    Restore default
596	                  </Button>
597	                </div>
598	              ) : null}
599	            </section>
600	          </div>
601	        </div>
602	      </div>
603	    </SidebarInset>
604	  );
605	}
