import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import {
  DEFAULT_THEME_ID,
  getTheme,
  listThemes,
  type Theme,
} from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";

// ---------------------------------------------------------------------------
// Module-level external store (mirrors the pattern in hooks/useTheme.ts)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let cachedId: string | null = null;
let cachedSnapshot: ThemeSnapshot | null = null;

interface ThemeSnapshot {
  themeId: string;
  theme: Theme;
}

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): string {
  if (typeof window === "undefined") return DEFAULT_THEME_ID;
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function getSnapshot(): ThemeSnapshot {
  const id = getStoredThemeId();
  if (cachedSnapshot && cachedId === id) return cachedSnapshot;
  cachedId = id;
  const theme = getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
  cachedSnapshot = { themeId: id, theme };
  return cachedSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const onStorage = (event: StorageEvent) => {
    if (event.key === STORAGE_KEY) emitChange();
  };
  window.addEventListener("storage", onStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", onStorage);
  };
}

// ---------------------------------------------------------------------------
// CSS custom-property application
// ---------------------------------------------------------------------------

function applyThemeCSSProperties(theme: Theme): void {
  const root = document.documentElement;
  const { colors } = theme;

  root.style.setProperty("--theme-background", colors.background);
  root.style.setProperty("--theme-foreground", colors.foreground);
  root.style.setProperty("--theme-accent", colors.accent);
  root.style.setProperty("--theme-sidebar", colors.sidebar);
  root.style.setProperty("--theme-editor", colors.editor);
  root.style.setProperty("--theme-terminal", colors.terminal);
  root.style.setProperty("--theme-status-bar", colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${String(theme.fontSize)}px`);
}

// Apply immediately on module load to prevent flash
applyThemeCSSProperties(getSnapshot().theme);

// ---------------------------------------------------------------------------
// React Context
// ---------------------------------------------------------------------------

interface ThemeContextValue {
  /** The currently active Theme object. */
  theme: Theme;
  /** Switch to a different theme by id. */
  setTheme: (id: string) => void;
  /** All available themes. */
  availableThemes: readonly Theme[];
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot, () => ({
    themeId: DEFAULT_THEME_ID,
    theme: getTheme(DEFAULT_THEME_ID)!,
  }));

  // Keep CSS custom properties in sync with the active theme
  useEffect(() => {
    applyThemeCSSProperties(snapshot.theme);
  }, [snapshot.theme]);

  const setTheme = useCallback((id: string) => {
    const resolved = getTheme(id);
    if (!resolved) return;
    localStorage.setItem(STORAGE_KEY, id);
    applyThemeCSSProperties(resolved);
    emitChange();
  }, []);

  const value: ThemeContextValue = {
    theme: snapshot.theme,
    setTheme,
    availableThemes: listThemes(),
  };

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Access the custom theme system.
 *
 * Returns the current `Theme` object, a `setTheme(id)` setter, and the full
 * list of `availableThemes`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

