import { cn } from "~/lib/utils";

function ThemeSwatch({ theme, selected, onClick }: {
  theme: Theme;
  selected: boolean;
  onClick: () => void;
}) {
  const { colors } = theme;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      aria-label={theme.name}
      className={cn(
        "group relative flex w-full items-center gap-3 rounded-lg border px-3 py-3 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onClick}
    >
      {/* Color swatch preview */}
      <div
        className="flex size-10 shrink-0 items-center justify-center overflow-hidden rounded-md border border-border/50"
        style={{ backgroundColor: colors.background }}
      >
        <div className="flex gap-0.5">
          <div
            className="h-5 w-1.5 rounded-sm"
            style={{ backgroundColor: colors.sidebar }}
          />
          <div className="flex flex-col gap-0.5">
            <div
              className="h-3 w-4 rounded-sm"
              style={{ backgroundColor: colors.editor }}
            />
            <div
              className="h-1.5 w-4 rounded-sm"
              style={{ backgroundColor: colors.terminal }}
            />
          </div>
        </div>
        <div
          className="absolute bottom-1.5 left-4.5 size-1.5 rounded-full"
          style={{ backgroundColor: colors.accent }}
        />
      </div>

      <div className="flex min-w-0 flex-1 flex-col">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="flex items-center gap-1.5 pt-0.5">
          {/* Inline color dots */}
          {(
            [
              ["bg", colors.background],
              ["fg", colors.foreground],
              ["accent", colors.accent],
            ] as const
          ).map(([label, color]) => (
            <span key={label} className="flex items-center gap-0.5">
              <span
                className="inline-block size-2.5 rounded-full border border-border/40"
                style={{ backgroundColor: color }}
              />
              <span className="text-[10px] text-muted-foreground">{label}</span>
            </span>
          ))}
        </span>
      </div>

      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
