export function ThemeSelector() {
  const { theme: activeTheme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Custom theme">
      {availableThemes.map((theme) => (
        <ThemeSwatch
          key={theme.id}
          theme={theme}
          selected={theme.id === activeTheme.id}
          onClick={() => setTheme(theme.id)}
        />
      ))}
    </div>
  );
}

