export interface ThemeColors {
  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  id: string;
  name: string;
  colors: ThemeColors;
  fontFamily: string;
  fontSize: number;
}

const builtInThemes: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    colors: {
      background: "#0a0a0b",
      foreground: "#e4e4e7",
      accent: "#6366f1",
      sidebar: "#111113",
      editor: "#0a0a0b",
      terminal: "#09090b",
      statusBar: "#111113",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    colors: {
      background: "#ffffff",
      foreground: "#18181b",
      accent: "#4f46e5",
      sidebar: "#f4f4f5",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#f4f4f5",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    colors: {
      background: "#020617",
      foreground: "#e2e8f0",
      accent: "#818cf8",
      sidebar: "#0f172a",
      editor: "#020617",
      terminal: "#010412",
      statusBar: "#0f172a",
    },
    fontFamily:
      '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
] as const;

export const DEFAULT_THEME_ID = "t3-dark";

export function getTheme(id: string): Theme | undefined {
  return builtInThemes.find((theme) => theme.id === id);
}

export function listThemes(): readonly Theme[] {
  return builtInThemes;
}

